    ssize_t bytes_read, total = 0;
    char *buffer = buf;
    while (count > 0) {
        bytes_read = read(fd, buffer, count);
        if (bytes_read < 0) {
            if (errno == EINTR)
                continue;
            return -1;
        }
        if (bytes_read == 0)
            break;
        buffer += bytes_read;
        total += bytes_read;
        count -= bytes_read;
    }
    return total;
}

